namespace Tests\Feature\Auth;

use App\Enums\UserRole;
use App\Models\AuditLog;
use App\Models\User;
use Illuminate\Foundation\Testing\RefreshDatabase;
use Illuminate\Support\Facades\DB;
use Tests\TestCase;

class SessionAndLogoutTest extends TestCase
{
    use RefreshDatabase;

    private function createAndAuthUser(): User
    {
        $user = User::create([
            'username' => 'testuser',
            'name' => 'Test User',
            'email' => 'test@researchhub.local',
            'password' => 'TestPassword123!@#',
            'role' => UserRole::Learner,
            'password_updated_at' => now(),
            'is_active' => true,
        ]);

        $this->actingAs($user);

        return $user;
    }

    public function test_logout_invalidates_session(): void
    {
        $user = $this->createAndAuthUser();

        $response = $this->post('/logout');

        $response->assertRedirect('/login');
        $this->assertGuest();
    }

    public function test_logout_creates_audit_log(): void
    {
        $user = $this->createAndAuthUser();

        $this->post('/logout');

        $this->assertDatabaseHas('audit_logs', [
            'user_id' => $user->id,
            'action' => 'logout',
        ]);
    }

    public function test_dashboard_requires_authentication(): void
    {
        $response = $this->get('/');
        $response->assertRedirect('/login');
    }

    public function test_expired_password_redirects_to_change(): void
    {
        $user = User::create([
            'username' => 'testuser',
            'name' => 'Test User',
            'email' => 'test@researchhub.local',
            'password' => 'TestPassword123!@#',
            'role' => UserRole::Learner,
            'password_updated_at' => now()->subDays(91),
            'is_active' => true,
        ]);

        $this->actingAs($user);

        $response = $this->get('/');
        $response->assertRedirect(route('auth.password.change'));
    }

    public function test_audit_log_is_immutable(): void
    {
        AuditLog::create([
            'user_id' => null,
            'action' => 'login',
            'ip_address' => '127.0.0.1',
            'severity' => 'info',
            'created_at' => now(),
        ]);

        $this->assertEquals(1, AuditLog::count());
        $this->assertNotNull(AuditLog::first()->created_at);
    }
}
"}

