use Livewire\Component;
use Livewire\WithPagination;

class CatalogList extends Component
{
    use WithPagination;

    public string $search = '';
    public string $category = '';
    public string $audience = '';
    public string $serviceType = '';
    public string $tag = '';
    public string $sortBy = 'earliest'; // earliest, price_low, price_high, title
    public string $priceFilter = ''; // free, paid

    protected $queryString = [
        'search' => ['except' => ''],
        'category' => ['except' => ''],
        'audience' => ['except' => ''],
        'serviceType' => ['except' => ''],
        'sortBy' => ['except' => 'earliest'],
    ];

    public function updatingSearch(): void
    {
        $this->resetPage();
    }

    public function updatingCategory(): void
    {
        $this->resetPage();
    }

    public function updatingAudience(): void
    {
        $this->resetPage();
    }

    public function clearFilters(): void
    {
        $this->reset(['search', 'category', 'audience', 'serviceType', 'tag', 'sortBy', 'priceFilter']);
        $this->resetPage();
    }

    public function toggleFavorite(int $serviceId, ToggleFavorite $action): void
    {
        $action->execute(auth()->user(), $serviceId);
    }

    public function render(DataDictionaryService $dictService)
    {
        $query = Service::active()->with(['tags', 'timeSlots' => function ($q) {
            $q->available()->orderBy('start_time')->limit(1);
        }]);

        if ($this->search) {
            $query->search($this->search);
        }

        if ($this->category) {
            $query->where('category', $this->category);
        }

        if ($this->audience) {
            $query->forAudience($this->audience);
        }

        if ($this->serviceType) {
            $query->where('service_type', $this->serviceType);
        }

        if ($this->tag) {
            $query->whereHas('tags', fn($q) => $q->where('slug', $this->tag));
        }

        if ($this->priceFilter === 'free') {
            $query->where('is_free', true);
        } elseif ($this->priceFilter === 'paid') {
            $query->where('is_free', false);
        }

        $query = match ($this->sortBy) {
            'price_low' => $query->orderBy('price', 'asc'),
            'price_high' => $query->orderBy('price', 'desc'),
            'title' => $query->orderBy('title', 'asc'),
            default => $query->orderBy('created_at', 'desc'),
        };

        $services = $query->paginate(12);

        $favoriteIds = auth()->check()
            ? UserFavorite::where('user_id', auth()->id())->pluck('service_id')->toArray()
            : [];

        return view('livewire.catalog.catalog-list', [
            'services' => $services,
            'favoriteIds' => $favoriteIds,
            'serviceTypes' => $dictService->getLabelsForType('service_type'),
            'audiences' => $dictService->getLabelsForType('eligibility'),
        ])->layout('components.layouts.app', ['title' => 'Service Catalog']);
    }
}
"}

