namespace App\Livewire\Reservations;

use App\Enums\ReservationStatus;
use App\Models\Reservation;
use App\Services\ReservationService;
use Livewire\Component;
use Livewire\WithPagination;

class ReservationDashboard extends Component
{
    use WithPagination;

    public string $filter = 'upcoming'; // upcoming, past, all
    public string $errorMessage = '';
    public string $successMessage = '';

    public function confirm(int $reservationId, ReservationService $service): void
    {
        $this->clearMessages();

        try {
            $reservation = Reservation::where('user_id', auth()->id())->findOrFail($reservationId);
            $service->confirm($reservation);
            $this->successMessage = 'Reservation confirmed!';
        } catch (\DomainException $e) {
            $this->errorMessage = $e->getMessage();
        }
    }

    public function cancel(int $reservationId, ReservationService $service): void
    {
        $this->clearMessages();

        try {
            $reservation = Reservation::where('user_id', auth()->id())->findOrFail($reservationId);
            $service->cancel($reservation);
            $this->successMessage = 'Reservation cancelled.';
        } catch (\DomainException $e) {
            $this->errorMessage = $e->getMessage();
        }
    }

    public function checkIn(int $reservationId, ReservationService $service): void
    {
        $this->clearMessages();

        try {
            $reservation = Reservation::where('user_id', auth()->id())->findOrFail($reservationId);
            $service->checkIn($reservation);
            $this->successMessage = 'Checked in successfully!';
        } catch (\DomainException $e) {
            $this->errorMessage = $e->getMessage();
        }
    }

    public function checkOut(int $reservationId, ReservationService $service): void
    {
        $this->clearMessages();

        try {
            $reservation = Reservation::where('user_id', auth()->id())->findOrFail($reservationId);
            $service->checkOut($reservation);
            $this->successMessage = 'Checked out. Thank you!';
        } catch (\DomainException $e) {
            $this->errorMessage = $e->getMessage();
        }
    }

    private function clearMessages(): void
    {
        $this->errorMessage = '';
        $this->successMessage = '';
    }

    public function render()
    {
        $query = Reservation::where('user_id', auth()->id())
            ->with(['service', 'timeSlot', 'penalties'])
            ->orderByDesc('created_at');

        if ($this->filter === 'upcoming') {
            $query->whereIn('status', [
                ReservationStatus::Pending->value,
                ReservationStatus::Confirmed->value,
            ])->whereHas('timeSlot', fn($q) => $q->where('start_time', '>=', now()));
        } elseif ($this->filter === 'past') {
            $query->whereIn('status', [
                ReservationStatus::Completed->value,
                ReservationStatus::Cancelled->value,
                ReservationStatus::NoShow->value,
                ReservationStatus::PartialAttendance->value,
            ]);
        }

        return view('livewire.reservations.reservation-dashboard', [
            'reservations' => $query->paginate(10),
        ])->layout('components.layouts.app', ['title' => 'My Reservations']);
    }
}
"}

