39	
40	        // Check for overlapping slots
41	        $overlap = TimeSlot::where('service_id', $this->service->id)
42	            ->where('is_active', true)
43	            ->where(function ($q) use ($startDateTime, $endDateTime) {
44	                $q->whereBetween('start_time', [$startDateTime, $endDateTime])
45	                  ->orWhereBetween('end_time', [$startDateTime, $endDateTime])
46	                  ->orWhere(function ($q2) use ($startDateTime, $endDateTime) {
