    }

    private function toCsv(Collection $data): string
    {
        if ($data->isEmpty()) {
            return '';
        }

        $output = fopen('php://temp', 'r+');
        fputcsv($output, array_keys($data->first()));

        foreach ($data as $row) {
            fputcsv($output, $row);
        }

        rewind($output);
        $csv = stream_get_contents($output);
        fclose($output);

        return $csv;
    }

    private function parseCsv(string $path): array
    {
        $rows = [];
        $handle = fopen($path, 'r');

        if ($handle === false) {
            throw new \RuntimeException('Cannot open file: ' . $path);
        }

        $headers = fgetcsv($handle);

        if ($headers === false) {
            fclose($handle);
            return [];
        }

        // Normalize headers
        $headers = array_map(fn($h) => trim(strtolower($h)), $headers);

        while (($line = fgetcsv($handle)) !== false) {
            if (count($line) === count($headers)) {
                $rows[] = array_combine($headers, $line);
            }
        }

        fclose($handle);

        return $rows;
    }

    private function parseJson(string $path): array
    {
        $content = file_get_contents($path);
        $data = json_decode($content, true);

        if (!is_array($data)) {
            throw new \RuntimeException('Invalid JSON file.');
        }

        // Handle both flat array and wrapped {"data": [...]}
        if (isset($data['data']) && is_array($data['data'])) {
            return $data['data'];
        }

        // If associative (single record), wrap it
        if (!empty($data) && !isset($data[0])) {
            return [$data];
        }

        return $data;
    }
