namespace App\Livewire\Admin;

use App\Jobs\ProcessImportChunk;
use App\Models\ImportBatch;
use App\Models\ImportConflict;
use App\Services\ImportExportService;
use Livewire\Component;
use Livewire\WithFileUploads;

class ImportManager extends Component
{
    use WithFileUploads;

    // Upload state
    public $file = null;
    public string $entity = 'services';
    public string $conflictStrategy = 'prefer_newest';

    // Mapping state
    public ?int $activeBatchId = null;
    public array $sourceHeaders = [];
    public array $destinationFields = [];
    public array $fieldMapping = [];

    // Progress state
    public string $step = 'upload'; // upload, mapping, processing, review, done
    public string $errorMessage = '';
    public string $successMessage = '';

    private const CHUNK_SIZE = 50;

    public function updatedFile(): void
    {
        $this->validate([
            'file' => 'required|file|max:10240|mimes:csv,txt,json',
        ]);
    }

    public function upload(ImportExportService $service): void
    {
        $this->validate([
            'file' => 'required|file|max:10240|mimes:csv,txt,json',
            'entity' => 'required|in:services,users',
        ]);

        $this->errorMessage = '';

        $ext = $this->file->getClientOriginalExtension();
        $format = in_array($ext, ['json']) ? 'json' : 'csv';

        $path = $this->file->store('imports', 'local');
        $fullPath = storage_path('app/' . $path);

        try {
            $this->sourceHeaders = $service->detectHeaders($fullPath, $format);
            $this->destinationFields = $service->getDestinationFields($this->entity);

            if (empty($this->sourceHeaders)) {
                $this->errorMessage = 'File appears to be empty or has no recognizable headers.';
                return;
            }

            // Auto-map matching field names
            $this->fieldMapping = [];
            foreach ($this->sourceHeaders as $header) {
                $normalized = strtolower(str_replace([' ', '-'], '_', $header));
                if (in_array($normalized, $this->destinationFields)) {
                    $this->fieldMapping[$header] = $normalized;
                } else {
                    $this->fieldMapping[$header] = '';
                }
            }

            // Create batch record
            $rows = $service->parseFile($fullPath, $format);

            $batch = ImportBatch::create([
                'user_id' => auth()->id(),
                'entity' => $this->entity,
                'filename' => $this->file->getClientOriginalName(),
                'format' => $format,
                'status' => 'mapping',
                'total_rows' => count($rows),
                'conflict_strategy' => $this->conflictStrategy,
            ]);

            $this->activeBatchId = $batch->id;
            $this->step = 'mapping';
        } catch (\Exception $e) {
            $this->errorMessage = 'Failed to parse file: ' . $e->getMessage();
        }
    }

    public function startProcessing(ImportExportService $service): void
    {
        $batch = ImportBatch::findOrFail($this->activeBatchId);

        // Require at least one mapped field
        $activeMappings = array_filter($this->fieldMapping);
        if (empty($activeMappings)) {
            $this->errorMessage = 'Please map at least one field.';
            return;
        }

        $batch->update([
            'field_mapping' => $this->fieldMapping,
            'conflict_strategy' => $this->conflictStrategy,
            'status' => 'processing',
        ]);

        // Parse and dispatch in chunks
        $path = storage_path('app/imports/' . basename($batch->filename));

        // Re-read from stored path
        $storedFiles = glob(storage_path('app/imports/*'));
        $latestFile = end($storedFiles);

        if (!$latestFile) {
            $this->errorMessage = 'Import file not found.';
            return;
        }

        $rows = $service->parseFile($latestFile, $batch->format);
        $chunks = array_chunk($rows, self::CHUNK_SIZE);

        $startIndex = 0;
        foreach ($chunks as $chunk) {
            ProcessImportChunk::dispatch($batch->id, $chunk, $startIndex);
            $startIndex += count($chunk);
        }

        $this->step = 'processing';
        $this->successMessage = "Import started! Processing {$batch->total_rows} rows in " . count($chunks) . " chunk(s).";
    }

    public function refreshProgress(): void
    {
        // Livewire will re-render with fresh batch data
    }

    public function resolveConflict(int $conflictId, string $resolution, ImportExportService $service): void
    {
        $conflict = ImportConflict::findOrFail($conflictId);
        $service->resolveConflict($conflict, $resolution);
    }

    public function finishReview(): void
    {
        $batch = ImportBatch::findOrFail($this->activeBatchId);

        if ($batch->unresolvedConflicts()->count() > 0) {
            $this->errorMessage = 'Please resolve all conflicts before finishing.';
            return;
        }

        $batch->update([
            'status' => 'completed',
            'completed_at' => now(),
        ]);

        $this->step = 'done';
    }

    public function startNew(): void
    {
        $this->reset();
        $this->step = 'upload';
    }

    public function render()
    {
        $batch = $this->activeBatchId ? ImportBatch::with('conflicts')->find($this->activeBatchId) : null;

        // Auto-advance from processing to review/done
        if ($batch && $this->step === 'processing') {
            if ($batch->isComplete() || $batch->status === 'pending_review') {
                $this->step = $batch->unresolvedConflicts()->count() > 0 ? 'review' : 'done';
            }
        }

        return view('livewire.admin.import-manager', [
            'batch' => $batch,
            'conflicts' => $batch?->unresolvedConflicts()->get() ?? collect(),
        ])->layout('components.layouts.app', ['title' => 'Import Data']);
    }
}
"}

