namespace App\Livewire\Admin;

use App\Enums\AuditAction;
use App\Services\AuditService;
use App\Services\ImportExportService;
use Livewire\Component;
use Symfony\Component\HttpFoundation\StreamedResponse;

class ExportManager extends Component
{
    public string $entity = 'services';
    public string $format = 'csv';
    public bool $includeSensitive = false;
    public bool $incrementalOnly = false;
    public string $sinceDate = '';
    public string $errorMessage = '';

    public function export(ImportExportService $service, AuditService $audit): StreamedResponse|null
    {
        $this->errorMessage = '';

        $options = [];

        if ($this->incrementalOnly && $this->sinceDate) {
            $options['since'] = $this->sinceDate;
        }

        if ($this->includeSensitive) {
            $options['include_sensitive'] = true;
        }

        try {
            $content = match ($this->entity) {
                'services' => $service->exportServices($this->format, $options),
                'users' => $service->exportUsers($this->format, $options),
                default => throw new \InvalidArgumentException('Invalid entity'),
            };

            $audit->log(AuditAction::DataExport, auth()->id(), [
                'entity' => $this->entity,
                'format' => $this->format,
                'include_sensitive' => $this->includeSensitive,
                'incremental' => $this->incrementalOnly,
            ]);

            $filename = $this->entity . '_export_' . now()->format('Y-m-d_His') . '.' . $this->format;
            $mimeType = $this->format === 'json' ? 'application/json' : 'text/csv';

            return response()->streamDownload(function () use ($content) {
                echo $content;
            }, $filename, [
                'Content-Type' => $mimeType,
            ]);
        } catch (\Exception $e) {
            $this->errorMessage = 'Export failed: ' . $e->getMessage();
            return null;
        }
    }

    public function render()
    {
        return view('livewire.admin.export-manager')
            ->layout('components.layouts.app', ['title' => 'Export Data']);
    }
}
"}

