# ResearchHub - Test Runner (Windows PowerShell)
# Runs all PHPUnit tests inside Docker, then validates Docker health.
#
$ErrorActionPreference = "Continue"

$pass = 0
$fail = 0

function Log($msg)  { Write-Host "[$(Get-Date -Format 'HH:mm:ss')]" -ForegroundColor Cyan -NoNewline; Write-Host " $msg" }
function Pass($msg) { Write-Host "  PASS" -ForegroundColor Green -NoNewline; Write-Host " $msg"; $script:pass++ }
function Fail($msg) { Write-Host "  FAIL" -ForegroundColor Red -NoNewline; Write-Host " $msg"; $script:fail++ }
function Warn($msg) { Write-Host "  WARN" -ForegroundColor Yellow -NoNewline; Write-Host " $msg" }

Write-Host ""
Write-Host "=============================================="
Write-Host "  ResearchHub - Full Test & Health Check"
Write-Host "=============================================="
Write-Host ""

# --- STEP 1: Ensure Docker is running ---
Log "Checking Docker..."
try {
    docker info 2>&1 | Out-Null
    if ($LASTEXITCODE -ne 0) { throw "Docker not running" }
    Pass "Docker daemon is running"
} catch {
    Fail "Docker is not running. Start Docker Desktop first."
    exit 1
}

# --- STEP 2: Ensure containers are up ---
Log "Checking containers..."
$running = (docker compose ps --status running -q 2>$null | Measure-Object -Line).Lines
if ($running -lt 4) {
    Warn "Only $running containers running. Starting stack..."

    # Generate TLS cert if missing
    if (-not (Test-Path "docker/nginx/ssl/server.crt")) {
        Log "Generating self-signed TLS certificate..."
        if (Get-Command openssl -ErrorAction SilentlyContinue) {
            bash docker/nginx/generate-cert.sh 2>$null
        } else {
            Warn "openssl not found - skipping TLS cert generation"
        }
    }

    docker compose up -d --build 2>&1 | Select-Object -Last 5

    Log "Waiting for containers to be healthy..."
    Start-Sleep -Seconds 10
}

# --- STEP 3: Verify each container ---
Log "Verifying container health..."
$services = @("app", "db", "redis", "nginx", "queue", "scheduler")
foreach ($svc in $services) {
    $status = docker compose ps $svc --format '{{.State}}' 2>$null
    if ($status -eq "running") {
        Pass "Container '$svc' is running"
    } else {
        Fail "Container '$svc' is $status"
    }
}

# --- STEP 4: Verify database connectivity ---
Log "Checking database connectivity..."
$dbCheck = docker compose exec -T app php artisan tinker --execute="DB::select('SELECT 1');" 2>&1
if ($LASTEXITCODE -eq 0) {
    Pass "PostgreSQL connection OK"
} else {
    Fail "Cannot connect to PostgreSQL"
    Write-Host ""
    Write-Host "Tip: Run 'docker compose exec app php artisan migrate --force' first."
    exit 1
}

# --- STEP 5: Verify Redis connectivity ---
Log "Checking Redis connectivity..."
$redisCheck = docker compose exec -T redis redis-cli ping 2>$null
if ($redisCheck -match "PONG") {
    Pass "Redis connection OK"
} else {
    Fail "Cannot connect to Redis"
}

# --- STEP 6: Run migrations ---
Log "Running migrations..."
docker compose exec -T app php artisan migrate --force 2>&1 | Select-Object -Last 3

# --- STEP 7: Run PHPUnit tests ---
Write-Host ""
Write-Host "=============================================="
Write-Host "  Running PHPUnit Tests"
Write-Host "=============================================="
Write-Host ""

$testOutput = docker compose exec -T app php artisan test 2>&1
$testExit = $LASTEXITCODE

$testOutput | ForEach-Object { Write-Host $_ }

if ($testExit -eq 0) {
    Pass "All PHPUnit tests passed"
} else {
    Fail "Some PHPUnit tests failed (exit code: $testExit)"
}

# --- STEP 8: Verify HTTP endpoints ---
Write-Host ""
Log "Checking HTTP endpoints..."

$baseUrl = ""

# Try HTTPS first (port 4443), fall back to HTTP (port 4000)
try {
    $httpsCode = (Invoke-WebRequest -Uri "https://localhost:4443/login" -SkipCertificateCheck -MaximumRedirection 0 -ErrorAction SilentlyContinue).StatusCode
    if ($httpsCode -eq 200) {
        $baseUrl = "https://localhost:4443"
        Pass "HTTPS endpoint OK (port 4443)"
    }
} catch {}

if (-not $baseUrl) {
    try {
        $httpCode = (Invoke-WebRequest -Uri "http://localhost:4000/login" -MaximumRedirection 0 -ErrorAction SilentlyContinue).StatusCode
        if ($httpCode -eq 200) {
            $baseUrl = "http://localhost:4000"
            Pass "HTTP endpoint OK (port 4000)"
        }
    } catch {}
}

if (-not $baseUrl) {
    Fail "No HTTP/HTTPS endpoint responding"
}

if ($baseUrl) {
    $skipCert = if ($baseUrl -match "https") { @{SkipCertificateCheck = $true} } else { @{} }

    # Login page
    try {
        $r = Invoke-WebRequest -Uri "$baseUrl/login" @skipCert -ErrorAction SilentlyContinue
        if ($r.StatusCode -eq 200) { Pass "GET /login -> 200" } else { Fail "GET /login -> $($r.StatusCode)" }
    } catch { Fail "GET /login -> error" }

    # Register page
    try {
        $r = Invoke-WebRequest -Uri "$baseUrl/register" @skipCert -ErrorAction SilentlyContinue
        if ($r.StatusCode -eq 200) { Pass "GET /register -> 200" } else { Fail "GET /register -> $($r.StatusCode)" }
    } catch { Fail "GET /register -> error" }

    # Health check
    try {
        $r = Invoke-WebRequest -Uri "$baseUrl/up" @skipCert -ErrorAction SilentlyContinue
        if ($r.StatusCode -eq 200) { Pass "GET /up -> 200 (health check)" } else { Fail "GET /up -> $($r.StatusCode)" }
    } catch { Fail "GET /up -> error" }
}

# --- STEP 9: Check queue worker ---
Log "Checking queue worker..."
$queueLogs = docker compose logs queue --tail=5 2>&1
if ($queueLogs -match "error|fatal|exception") {
    $queueErr = ($queueLogs | Select-String "error|fatal|exception" | Select-Object -First 1).Line
    Fail "Queue worker has errors: $queueErr"
} else {
    Pass "Queue worker running clean"
}

# --- STEP 10: Check scheduler ---
Log "Checking scheduler..."
$schedLogs = docker compose logs scheduler --tail=5 2>&1
if ($schedLogs -match "fatal|exception") {
    Fail "Scheduler has errors"
} else {
    Pass "Scheduler running clean"
}

# --- SUMMARY ---
Write-Host ""
Write-Host "=============================================="
Write-Host "  Results: " -NoNewline
Write-Host "$pass passed" -ForegroundColor Green -NoNewline
Write-Host ", " -NoNewline
Write-Host "$fail failed" -ForegroundColor Red
Write-Host "=============================================="
Write-Host ""

if ($fail -gt 0) {
    Write-Host "Some checks failed. Review the output above." -ForegroundColor Red
    exit 1
} else {
    Write-Host "All checks passed! System is healthy." -ForegroundColor Green
    exit 0
}
"}

