    } catch { Fail "GET /login -> error" }

    # Register page
    try {
        $r = Invoke-WebRequest -Uri "$baseUrl/register" @skipCert -ErrorAction SilentlyContinue
        if ($r.StatusCode -eq 200) { Pass "GET /register -> 200" } else { Fail "GET /register -> $($r.StatusCode)" }
    } catch { Fail "GET /register -> error" }

    # Health check
    try {
        $r = Invoke-WebRequest -Uri "$baseUrl/up" @skipCert -ErrorAction SilentlyContinue
        if ($r.StatusCode -eq 200) { Pass "GET /up -> 200 (health check)" } else { Fail "GET /up -> $($r.StatusCode)" }
    } catch { Fail "GET /up -> error" }
}

# --- STEP 9: Check queue worker ---
Log "Checking queue worker..."
$queueLogs = docker compose logs queue --tail=5 2>&1
if ($queueLogs -match "error|fatal|exception") {
    $queueErr = ($queueLogs | Select-String "error|fatal|exception" | Select-Object -First 1).Line
    Fail "Queue worker has errors: $queueErr"
} else {
    Pass "Queue worker running clean"
}

# --- STEP 10: Check scheduler ---
Log "Checking scheduler..."
$schedLogs = docker compose logs scheduler --tail=5 2>&1
if ($schedLogs -match "fatal|exception") {
    Fail "Scheduler has errors"
} else {
    Pass "Scheduler running clean"
}

# --- SUMMARY ---
Write-Host ""
Write-Host "=============================================="
Write-Host "  Results: " -NoNewline
Write-Host "$pass passed" -ForegroundColor Green -NoNewline
Write-Host ", " -NoNewline
Write-Host "$fail failed" -ForegroundColor Red
Write-Host "=============================================="
Write-Host ""

if ($fail -gt 0) {
    Write-Host "Some checks failed. Review the output above." -ForegroundColor Red
    exit 1
} else {
    Write-Host "All checks passed! System is healthy." -ForegroundColor Green
    exit 0
}
"}

