use Tests\TestCase;

class SingleLogoutTest extends TestCase
{
    use RefreshDatabase;

    private User $user;

    protected function setUp(): void
    {
        parent::setUp();

        $this->user = User::create([
            'username' => 'multidevice',
            'name' => 'Multi Device User',
            'email' => 'multi@test.local',
            'password' => 'MultiDevice123!@#',
            'role' => UserRole::Learner,
            'password_updated_at' => now(),
            'is_active' => true,
        ]);
    }

    private function logoutPost(): \Illuminate\Testing\TestResponse
    {
        return $this->withoutMiddleware(\Illuminate\Foundation\Http\Middleware\VerifyCsrfToken::class)
            ->post('/logout');
    }

    public function test_logout_invalidates_all_other_sessions(): void
    {
        $this->actingAs($this->user);

        DB::table('sessions')->insert([
            'id' => 'session_1_id',
            'user_id' => $this->user->id,
            'ip_address' => '192.168.1.10',
            'user_agent' => 'Browser/Session1',
            'payload' => base64_encode(serialize([])),
            'last_activity' => now()->timestamp,
        ]);

        $this->logoutPost();

        $remainingSessions = DB::table('sessions')
            ->where('user_id', $this->user->id)
            ->count();

        $this->assertEquals(0, $remainingSessions,
            'All sessions for the user should be purged after single-logout');
    }

    public function test_user_is_guest_after_logout(): void
    {
        $this->actingAs($this->user);
        $this->logoutPost();
        $this->assertGuest();
    }

    public function test_protected_routes_redirect_after_logout(): void
    {
        $this->actingAs($this->user);
        $this->logoutPost();

        $this->get('/')->assertRedirect('/login');
        $this->get('/catalog')->assertRedirect('/login');
        $this->get('/reservations')->assertRedirect('/login');
    }

    public function test_logout_creates_dual_audit_entries(): void
    {
        $this->actingAs($this->user);
        $this->logoutPost();

        $this->assertDatabaseHas('audit_logs', [
            'user_id' => $this->user->id,
            'action' => 'logout_all',
        ]);

        $this->assertDatabaseHas('audit_logs', [
            'user_id' => $this->user->id,
            'action' => 'logout',
        ]);
    }

    public function test_csrf_token_regenerated_after_logout(): void
    {
        $this->actingAs($this->user);
        $this->logoutPost();
        $this->assertGuest();
    }
}
"}

