# ResearchHub - Full Build, Run & Test (Windows PowerShell)
# Builds Docker from scratch, starts all services, runs tests, verifies health.
#
$ErrorActionPreference = "Continue"

$pass = 0
$fail = 0
$stepNum = 0

function Step($msg) { $script:stepNum++; Write-Host ""; Write-Host "[$script:stepNum] $msg" -ForegroundColor White -BackgroundColor DarkBlue; Write-Host ("─" * 45) }
function Log($msg)  { Write-Host "  >>>" -ForegroundColor Cyan -NoNewline; Write-Host " $msg" }
function Pass($msg) { Write-Host "  PASS" -ForegroundColor Green -NoNewline; Write-Host " $msg"; $script:pass++ }
function Fail($msg) { Write-Host "  FAIL" -ForegroundColor Red -NoNewline; Write-Host " $msg"; $script:fail++ }
function Warn($msg) { Write-Host "  WARN" -ForegroundColor Yellow -NoNewline; Write-Host " $msg" }

Write-Host ""
Write-Host "================================================" -ForegroundColor White
Write-Host "  ResearchHub - Build, Run & Test Pipeline" -ForegroundColor White
Write-Host "================================================" -ForegroundColor White
Write-Host ""

# ─── STEP 1 ───
Step "Checking prerequisites"

Log "Checking Docker daemon..."
try {
    docker info 2>&1 | Out-Null
    if ($LASTEXITCODE -ne 0) { throw "Docker not running" }
    Pass "Docker daemon is running"
} catch {
    Fail "Docker is not running. Start Docker Desktop first."
    exit 1
}

$composeVer = docker compose version --short 2>$null
Pass "docker compose $composeVer"

# ─── STEP 2 ───
Step "Tearing down old containers (clean slate)"

Log "Stopping and removing existing containers + volumes..."
docker compose down -v --remove-orphans 2>&1 | ForEach-Object { Write-Host "  $_" }
Pass "Old containers removed"

# ─── STEP 3 ───
Step "Generating TLS certificate (if needed)"

if (Test-Path "docker/nginx/generate-cert.sh") {
    if (-not (Test-Path "docker/nginx/ssl/server.crt")) {
        Log "Generating self-signed TLS cert..."
        if (Get-Command openssl -ErrorAction SilentlyContinue) {
            bash docker/nginx/generate-cert.sh 2>&1 | ForEach-Object { Write-Host "  $_" }
            if (Test-Path "docker/nginx/ssl/server.crt") { Pass "TLS certificate generated" }
            else { Warn "TLS cert generation failed (HTTP fallback)" }
        } else {
            Warn "openssl not found - skipping TLS"
        }
    } else {
        Pass "TLS certificate already exists"
    }
} else {
    Warn "No generate-cert.sh found"
}

# ─── STEP 4 ───
Step "Building Docker images"

Log "Building app, queue, and scheduler images..."
$buildStart = Get-Date
docker compose build 2>&1 | ForEach-Object { Write-Host "  $_" }
$buildSecs = [int](New-TimeSpan -Start $buildStart -End (Get-Date)).TotalSeconds

if ($LASTEXITCODE -eq 0) {
    Pass "Docker images built (${buildSecs}s)"
} else {
    Fail "Docker build failed"
    exit 1
}

# ─── STEP 5 ───
Step "Starting all containers"

Log "Starting 6 services: app, nginx, db, redis, queue, scheduler..."
docker compose up -d 2>&1 | ForEach-Object { Write-Host "  $_" }

Log "Waiting for PostgreSQL and Redis healthchecks..."
$wait = 0
$maxWait = 60
while ($wait -lt $maxWait) {
    $dbH = docker compose ps db --format '{{.Health}}' 2>$null
    $redisH = docker compose ps redis --format '{{.Health}}' 2>$null
    if ($dbH -eq "healthy" -and $redisH -eq "healthy") { break }
    Start-Sleep -Seconds 2
    $wait += 2
    Write-Host "  Waiting... (${wait}s) db=$dbH redis=$redisH"
}

if ($wait -ge $maxWait) {
    Fail "Containers did not become healthy within ${maxWait}s"
    docker compose ps -a 2>&1 | ForEach-Object { Write-Host "  $_" }
    exit 1
}
Pass "All containers healthy (${wait}s)"

# ─── STEP 6 ───
Step "Verifying all 6 containers are running"

$services = @("app", "db", "redis", "nginx", "queue", "scheduler")
foreach ($svc in $services) {
    $status = docker compose ps $svc --format '{{.State}}' 2>$null
    if ($status -eq "running") { Pass "$svc is running" }
    else { Fail "$svc is $status" }
}

# ─── STEP 7 ───
Step "Installing PHP dependencies"

Log "Running composer install inside container..."
docker compose exec -T app composer install --no-interaction 2>&1 | Select-Object -Last 5 | ForEach-Object { Write-Host "  $_" }
if ($LASTEXITCODE -eq 0) { Pass "Composer dependencies installed" }
else { Fail "Composer install failed"; exit 1 }

# ─── STEP 8 ───
Step "Running database migrations"

Log "Applying all migrations..."
docker compose exec -T app php artisan migrate:fresh --force 2>&1 | ForEach-Object { Write-Host "  $_" }
if ($LASTEXITCODE -eq 0) { Pass "Migrations applied" }
else { Fail "Migrations failed"; exit 1 }

# ─── STEP 9 ───
Step "Seeding database"

Log "Seeding sample data (users, services, time slots)..."
docker compose exec -T app php artisan db:seed --force 2>&1 | ForEach-Object { Write-Host "  $_" }
if ($LASTEXITCODE -eq 0) { Pass "Database seeded" }
else { Warn "Seeder had issues (non-critical)" }

# ─── STEP 10 ───
Step "Verifying service connectivity"

Log "Testing PostgreSQL..."
docker compose exec -T app php artisan tinker --execute="DB::select('SELECT 1');" 2>&1 | Out-Null
if ($LASTEXITCODE -eq 0) { Pass "PostgreSQL connection OK" }
else { Fail "Cannot connect to PostgreSQL" }

Log "Testing Redis..."
$redisPing = docker compose exec -T redis redis-cli ping 2>$null
if ($redisPing -match "PONG") { Pass "Redis connection OK" }
else { Fail "Cannot connect to Redis" }

# ─── STEP 11 ───
Step "Running PHPUnit test suite (199 tests)"

Log "Resetting database for clean test run..."
docker compose exec -T app php artisan migrate:fresh --force 2>&1 | Out-Null

Write-Host ""
docker compose exec -T app php artisan test 2>&1 | ForEach-Object { Write-Host $_ }
$testExit = $LASTEXITCODE
Write-Host ""

if ($testExit -eq 0) { Pass "All PHPUnit tests passed" }
else { Fail "Some tests failed (exit code: $testExit)" }

# ─── STEP 12 ───
Step "Re-seeding database for live use"

Log "Restoring sample data after test run..."
docker compose exec -T app php artisan migrate:fresh --force 2>&1 | Out-Null
docker compose exec -T app php artisan db:seed --force 2>&1 | Out-Null
Pass "Database re-seeded with sample data"

# ─── STEP 13 ───
Step "Verifying HTTP endpoints"

$baseUrl = ""
try {
    $code = (Invoke-WebRequest -Uri "https://localhost:4443/login" -SkipCertificateCheck -MaximumRedirection 0 -ErrorAction SilentlyContinue).StatusCode
    if ($code -eq 200) { $baseUrl = "https://localhost:4443"; Pass "HTTPS available at https://localhost:4443" }
} catch {}

if (-not $baseUrl) {
    try {
        $code = (Invoke-WebRequest -Uri "http://localhost:4000/login" -MaximumRedirection 0 -ErrorAction SilentlyContinue).StatusCode
        if ($code -eq 200) { $baseUrl = "http://localhost:4000"; Pass "HTTP available at http://localhost:4000" }
    } catch {}
}

if (-not $baseUrl) { Fail "No endpoint responding on port 4000 or 4443" }

if ($baseUrl) {
    $skipCert = if ($baseUrl -match "https") { @{SkipCertificateCheck = $true} } else { @{} }

    $endpoints = @(
        @{Path="/login"; Expected=200; Desc="Login page"},
        @{Path="/register"; Expected=200; Desc="Register page"},
        @{Path="/up"; Expected=200; Desc="Health check"}
    )

    foreach ($ep in $endpoints) {
        try {
            $r = Invoke-WebRequest -Uri "$baseUrl$($ep.Path)" @skipCert -MaximumRedirection 0 -ErrorAction SilentlyContinue
            if ($r.StatusCode -eq $ep.Expected) { Pass "GET $($ep.Path) -> $($r.StatusCode) ($($ep.Desc))" }
            else { Fail "GET $($ep.Path) -> $($r.StatusCode) (expected $($ep.Expected))" }
        } catch { Fail "GET $($ep.Path) -> error" }
    }
}

# ─── STEP 14 ───
Step "Checking background workers"

Log "Queue worker..."
$queueSt = docker compose ps queue --format '{{.State}}' 2>$null
if ($queueSt -eq "running") { Pass "Queue worker running" }
else { Fail "Queue worker is $queueSt" }

Log "Scheduler..."
$schedSt = docker compose ps scheduler --format '{{.State}}' 2>$null
if ($schedSt -eq "running") { Pass "Scheduler running" }
else { Fail "Scheduler is $schedSt" }

# ─── SUMMARY ───
Write-Host ""
Write-Host "================================================" -ForegroundColor White
Write-Host "  " -NoNewline
Write-Host "$pass passed" -ForegroundColor Green -NoNewline
Write-Host "  " -NoNewline
Write-Host "$fail failed" -ForegroundColor Red
Write-Host "================================================" -ForegroundColor White
Write-Host ""

if ($baseUrl) {
    Write-Host "  Frontend:  $baseUrl" -ForegroundColor Cyan
    Write-Host ""
    Write-Host "  Default credentials:"
    Write-Host "    Admin:   admin   / Admin123!@#456"
    Write-Host "    Editor:  editor  / Editor123!@#456"
    Write-Host "    Learner: learner / Learner123!@#456"
    Write-Host ""
}

if ($fail -gt 0) {
    Write-Host "Some checks failed. Review output above." -ForegroundColor Red
    exit 1
} else {
    Write-Host "All checks passed! System is ready." -ForegroundColor Green
    exit 0
}
"}

