16	    public function login(Request $request, AttemptLogin $action): JsonResponse
17	    {
18	        $request->validate([
19	            'username' => 'required|string',
20	            'password' => 'required|string',
21	            'captcha' => 'nullable|string',
22	        ]);
23	
24	        $result = $action->execute(
25	            $request->username,
26	            $request->password,
27	            $request->captcha,
28	            establishSession: true,
29	        );
30	
31	        if ($result->isSuccess()) {
32	            return response()->json([
33	                'user' => new UserResource($result->user),
34	            ]);
35	        }
36	
37	        if ($result->isPasswordExpired()) {
38	            return response()->json([
39	                'error' => 'password_expired',
40	                'message' => $result->message,
41	            ], 403);
42	        }
43	
44	        if ($result->isCaptchaRequired()) {
45	            return response()->json([
46	                'error' => 'captcha_required',
47	                'message' => $result->message,
48	            ], 422);
49	        }
50	
51	        // locked or failed
52	        $statusCode = $result->status === 'locked' ? 423 : 401;
53	
54	        return response()->json([
55	            'error' => $result->status,
56	            'message' => $result->message,
57	        ], $statusCode);
58	    }
