69	        \Illuminate\Support\Facades\Auth::guard('web')->logout();
70	
71	        if ($request->hasSession()) {
72	            $request->session()->invalidate();
73	            $request->session()->regenerateToken();
74	        }
75	
76	        return response()->json(['message' => 'Logged out.']);
77	    }
