79	    public function stepUpVerify(Request $request, AuditService $audit): JsonResponse
80	    {
81	        $request->validate([
82	            'password' => 'required|string',
83	        ]);
84	
85	        $user = $request->user();
86	
87	        if (!Hash::check($request->password, $user->password)) {
88	            $audit->log(AuditAction::StepUpFailed, $user->id, [], 'warning');
89	            return response()->json(['error' => 'Invalid password.'], 403);
