167	    public function importUpload(Request $request, ImportExportService $service): JsonResponse
168	    {
169	        $request->validate([
170	            'file' => 'required_without:stored_path|file|max:10240|mimes:csv,txt,json',
171	            'stored_path' => 'required_without:file|string',
172	            'original_filename' => 'nullable|string',
173	            'entity' => 'required|in:services,users',
174	            'conflict_strategy' => 'required|in:skip,prefer_newest,admin_override',
175	        ]);
176	
177	        // Support both direct file upload and pre-stored path (from Livewire)
178	        if ($request->hasFile('file')) {
179	            $file = $request->file('file');
180	            $ext = $file->getClientOriginalExtension();
181	            $format = in_array($ext, ['json']) ? 'json' : 'csv';
182	            $path = $file->store('imports', 'local');
183	            $originalFilename = $file->getClientOriginalName();
184	        } else {
185	            $path = $request->input('stored_path');
186	            $format = str_ends_with(strtolower($path), '.json') ? 'json' : 'csv';
187	            $originalFilename = $request->input('original_filename', basename($path));
188	        }
189	
190	        $fullPath = storage_path('app/' . $path);
191	
192	        $headers = $service->detectHeaders($fullPath, $format);
193	
194	        if (empty($headers)) {
195	            return response()->json(['error' => 'File appears to be empty or has no recognizable headers.'], 422);
196	        }
197	
198	        $rows = $service->parseFile($fullPath, $format);
199	
200	        // Auto-map matching field names
201	        $destinationFields = $service->getDestinationFields($request->input('entity'));
202	        $fieldMapping = [];
203	        foreach ($headers as $header) {
204	            $normalized = strtolower(str_replace([' ', '-'], '_', $header));
205	            $fieldMapping[$header] = in_array($normalized, $destinationFields) ? $normalized : '';
206	        }
207	
208	        $batch = ImportBatch::create([
209	            'user_id' => $request->user()->id,
210	            'entity' => $request->input('entity'),
211	            'filename' => $originalFilename,
212	            'stored_path' => $path,
213	            'format' => $format,
214	            'status' => 'mapping',
215	            'total_rows' => count($rows),
216	            'conflict_strategy' => $request->input('conflict_strategy'),
217	        ]);
218	
219	        return response()->json([
220	            'data' => [
221	                'batch_id' => $batch->id,
222	                'source_headers' => $headers,
223	                'destination_fields' => $destinationFields,
224	                'field_mapping' => $fieldMapping,
225	                'total_rows' => count($rows),
226	            ],
