# ResearchHub - Test Runner
# Runs Unit, Integration, Frontend, and API test suites.
# Detects whether PHP is local or needs Docker, then runs accordingly.
#
$ErrorActionPreference = "Continue"

function Pass($msg) { Write-Host "  PASS " -ForegroundColor Green -NoNewline; Write-Host $msg }
function Fail($msg) { Write-Host "  FAIL " -ForegroundColor Red -NoNewline; Write-Host $msg }

# Detect runtime
if (Get-Command php -ErrorAction SilentlyContinue) {
    $run = "php"
} else {
    $state = docker compose ps app --format '{{.State}}' 2>$null
    if ($state -ne "running") {
        Write-Host "No local PHP and Docker app container is not running." -ForegroundColor Red
        Write-Host "  Start Docker first:  docker compose up -d"
        exit 1
    }
    $run = "docker compose exec -T app php"
}

Write-Host "`n================================================"
Write-Host "  ResearchHub - Test Runner"
Write-Host "================================================"

# Unit Tests
Write-Host "`n[1/4] Unit Tests"
Write-Host ("─" * 45)
Invoke-Expression "$run artisan migrate:fresh --force --quiet" 2>$null
Invoke-Expression "$run artisan test --testsuite=Unit" 2>&1 | ForEach-Object { Write-Host $_ }
$unitExit = $LASTEXITCODE

# Integration Tests
Write-Host "`n[2/4] Integration Tests"
Write-Host ("─" * 45)
Invoke-Expression "$run artisan migrate:fresh --force --quiet" 2>$null
Invoke-Expression "$run artisan test --testsuite=Feature" 2>&1 | ForEach-Object { Write-Host $_ }
$featureExit = $LASTEXITCODE

# Frontend Tests (Livewire)
Write-Host "`n[3/4] Frontend Tests (Livewire)"
Write-Host ("─" * 45)
Invoke-Expression "$run artisan migrate:fresh --force --quiet" 2>$null
Invoke-Expression "$run artisan test --testsuite=Feature --filter='Livewire|Catalog|Auth\\Login|Auth\\Register'" 2>&1 | ForEach-Object { Write-Host $_ }
$frontendExit = $LASTEXITCODE

# API Tests
Write-Host "`n[4/4] API Tests"
Write-Host ("─" * 45)
Invoke-Expression "$run artisan migrate:fresh --force --quiet" 2>$null
Invoke-Expression "$run artisan test --testsuite=Api" 2>&1 | ForEach-Object { Write-Host $_ }
$apiExit = $LASTEXITCODE

# Summary
Write-Host "`n================================================"
if ($unitExit -eq 0) { Pass "Unit tests" } else { Fail "Unit tests" }
if ($featureExit -eq 0) { Pass "Integration tests" } else { Fail "Integration tests" }
if ($frontendExit -eq 0) { Pass "Frontend tests" } else { Fail "Frontend tests" }
if ($apiExit -eq 0) { Pass "API tests" } else { Fail "API tests" }
Write-Host "================================================`n"

$total = $unitExit + $featureExit + $frontendExit + $apiExit
if ($total -eq 0) { Write-Host "All test suites passed." -ForegroundColor Green } else { Write-Host "Some suites failed." -ForegroundColor Red }
exit $total
"}

